import{_ as a,o as e,c as d,ae as r}from"./chunks/framework.Czhw_PXq.js";const c=JSON.parse('{"title":"Postman 配置","description":"","frontmatter":{},"headers":[],"relativePath":"zh/settings/postman.md","filePath":"zh/settings/postman.md","lastUpdated":1776813413000}'),s={name:"zh/settings/postman.md"};function o(n,t,h,l,i,p){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="postman-配置" tabindex="-1">Postman 配置 <a class="header-anchor" href="#postman-配置" aria-label="Permalink to &quot;Postman 配置&quot;">​</a></h1><h2 id="ide-设置" tabindex="-1">IDE 设置 <a class="header-anchor" href="#ide-设置" aria-label="Permalink to &quot;IDE 设置&quot;">​</a></h2><p>在 IDE 中配置 Postman 设置：</p><p><kbd>Settings</kbd> &gt; <kbd>Other Settings</kbd> &gt; <kbd>EasyApi</kbd> &gt; <kbd>Postman</kbd></p><table tabindex="0"><thead><tr><th>设置项</th><th>说明</th></tr></thead><tbody><tr><td>Token</td><td>Postman API Token</td></tr><tr><td>Workspace</td><td>Postman 工作区 ID</td></tr><tr><td>Export Mode</td><td>导出时如何处理集合（见下方）</td></tr><tr><td>Build Example</td><td>是否在导出的集合中构建示例数据（默认：开启）</td></tr><tr><td>JSON5 Format Type</td><td>JSON5 格式的使用范围（见下方）</td></tr><tr><td>Collections</td><td>模块与集合的映射（每行一个 <code>module:collectionId</code>）</td></tr></tbody></table><h3 id="获取-postman-api-key" tabindex="-1">获取 Postman API Key <a class="header-anchor" href="#获取-postman-api-key" aria-label="Permalink to &quot;获取 Postman API Key&quot;">​</a></h3><ol><li>登录 Postman</li><li>进入 Account Settings &gt; API Keys</li><li>生成新的 API Key</li></ol><h3 id="导出模式" tabindex="-1">导出模式 <a class="header-anchor" href="#导出模式" aria-label="Permalink to &quot;导出模式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>说明</th></tr></thead><tbody><tr><td>CREATE_NEW</td><td>始终创建新集合（默认）</td></tr><tr><td>UPDATE_EXISTING</td><td>尝试按模块更新已有集合</td></tr></tbody></table><h2 id="配置文件规则" tabindex="-1">配置文件规则 <a class="header-anchor" href="#配置文件规则" aria-label="Permalink to &quot;配置文件规则&quot;">​</a></h2><p>以下规则可以在配置文件（<code>.easy.api.config</code>）中设置：</p><table tabindex="0"><thead><tr><th>规则</th><th>说明</th></tr></thead><tbody><tr><td><a href="/zh/settings/rules/postman_host">postman.host</a></td><td>Postman 基础 URL</td></tr><tr><td><a href="/zh/settings/rules/postman_prerequest">postman.prerequest</a></td><td>预请求脚本</td></tr><tr><td><a href="/zh/settings/rules/postman_test">postman.test</a></td><td>测试脚本</td></tr><tr><td><a href="/zh/settings/rules/postman_class_prerequest">postman.class.prerequest</a></td><td>类级别预请求脚本</td></tr><tr><td><a href="/zh/settings/rules/postman_class_test">postman.class.test</a></td><td>类级别测试脚本</td></tr><tr><td><a href="/zh/settings/rules/postman_collection_prerequest">postman.collection.prerequest</a></td><td>集合级别预请求事件</td></tr><tr><td><a href="/zh/settings/rules/postman_collection_test">postman.collection.test</a></td><td>集合级别测试事件</td></tr><tr><td><a href="/zh/settings/rules/postman_format_after">postman.format.after</a></td><td>格式化后钩子</td></tr></tbody></table><h3 id="json5-格式类型" tabindex="-1">JSON5 格式类型 <a class="header-anchor" href="#json5-格式类型" aria-label="Permalink to &quot;JSON5 格式类型&quot;">​</a></h3><p>控制导出的 Postman 集合中 JSON5 格式的使用范围：</p><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td>NONE</td><td>不使用 JSON5</td></tr><tr><td>REQUEST_ONLY</td><td>仅请求体使用 JSON5</td></tr><tr><td>RESPONSE_ONLY</td><td>仅响应体使用 JSON5</td></tr><tr><td>EXAMPLE_ONLY</td><td>仅示例使用 JSON5（默认）</td></tr><tr><td>ALL</td><td>始终使用 JSON5</td></tr></tbody></table>',15)])])}const b=a(s,[["render",o]]);export{c as __pageData,b as default};
